"use client";

import { useCallback, useEffect, useRef } from "react";
import { Plate, PlateContent, usePlateEditor } from "platejs/react";
import { cn } from "@/lib/utils";
import { articleBodyPlugins } from "./plugins/editor-kit";
import { EditorToolbar } from "./parts/editor-toolbar";
import {
  ARTICLE_BODY_DEFAULT_PLACEHOLDER,
  ARTICLE_BODY_EMPTY_VALUE,
  type ArticleBodyEditorProps,
  type ArticleBodyValue,
} from "./types";

const SAVE_KEY_DESCRIPTOR =
  typeof navigator !== "undefined" && /Mac/i.test(navigator.platform)
    ? "Cmd+S"
    : "Ctrl+S";

export function ArticleBodyEditor(props: ArticleBodyEditorProps) {
  const {
    value: controlledValue,
    defaultValue,
    onChange,
    onSave,
    readOnly = false,
    placeholder = ARTICLE_BODY_DEFAULT_PLACEHOLDER,
    onImageUpload,
    className,
    toolbarClassName,
    contentClassName,
    containerClassName,
    hideToolbar = false,
    autoFocus = false,
  } = props;

  const initialValue =
    controlledValue ?? defaultValue ?? ARTICLE_BODY_EMPTY_VALUE;

  const editor = usePlateEditor({
    plugins: articleBodyPlugins,
    value: initialValue,
    autoSelect: autoFocus ? "end" : undefined,
  });

  // Echo-guarded sync: when controlledValue prop changes from the outside,
  // mirror it into the editor without re-emitting onChange. Stored in a ref
  // (not state) — React Compiler-aware lint rejects setState in effect bodies,
  // and we don't want to trigger a re-render on this anyway.
  const lastSyncedValueRef = useRef<ArticleBodyValue>(initialValue);
  useEffect(() => {
    if (controlledValue && controlledValue !== lastSyncedValueRef.current) {
      editor.tf.setValue(controlledValue);
      lastSyncedValueRef.current = controlledValue;
    }
  }, [controlledValue, editor]);

  const handleChange = useCallback(
    ({ value }: { value: ArticleBodyValue }) => {
      lastSyncedValueRef.current = value;
      onChange?.(value);
    },
    [onChange]
  );

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "s" && onSave) {
        e.preventDefault();
        const current = editor.children as ArticleBodyValue;
        Promise.resolve(onSave(current)).catch((err) => {
          console.error("onSave failed", err);
        });
      }
    },
    [editor, onSave]
  );

  return (
    <div
      className={cn(
        "rounded-lg border border-border bg-card overflow-hidden",
        className
      )}
    >
      <Plate editor={editor} onChange={handleChange} readOnly={readOnly}>
        {!hideToolbar && !readOnly ? (
          <EditorToolbar
            className={toolbarClassName}
            onImageUpload={onImageUpload}
          />
        ) : null}

        <div
          className={cn(
            "max-h-150 overflow-y-auto px-6 py-4",
            containerClassName
          )}
        >
          <PlateContent
            placeholder={placeholder}
            className={cn(
              "min-h-50 focus:outline-none",
              "prose prose-sm dark:prose-invert max-w-none",
              "[&_:where(p,h1,h2,h3,h4)]:my-0",
              contentClassName
            )}
            onKeyDown={handleKeyDown}
            spellCheck
          />
        </div>

        {!readOnly && onSave ? (
          <div className="border-t border-border bg-muted/30 px-4 py-1.5 text-xs text-muted-foreground">
            Press{" "}
            <kbd className="rounded border border-border bg-muted px-1.5 py-0.5 font-mono text-[0.85em]">
              {SAVE_KEY_DESCRIPTOR}
            </kbd>{" "}
            to save
          </div>
        ) : null}
      </Plate>
    </div>
  );
}

import { createStaticEditor, PlateStatic } from "platejs/static";
import { cn } from "@/lib/utils";
import { articleBodyViewerPlugins } from "./plugins/viewer-kit";
import {
  ARTICLE_BODY_EMPTY_VALUE,
  type ArticleBodyValue,
  type ArticleBodyViewerProps,
} from "./types";

const VIEWER_PROSE_CLASSES =
  "prose prose-sm dark:prose-invert max-w-none [&_:where(p,h1,h2,h3,h4)]:my-0";

export function ArticleBodyViewer({
  value,
  className,
  fallback,
}: ArticleBodyViewerProps) {
  if (!value || value.length === 0) {
    if (fallback !== undefined) return <>{fallback}</>;
    return (
      <div className={cn(VIEWER_PROSE_CLASSES, className)}>
        <p className="text-muted-foreground">No content.</p>
      </div>
    );
  }

  const editor = createStaticEditor({
    plugins: articleBodyViewerPlugins,
    value: value as ArticleBodyValue,
  });

  return (
    <div className={cn(VIEWER_PROSE_CLASSES, className)}>
      <PlateStatic editor={editor} value={value as ArticleBodyValue} />
    </div>
  );
}

// Re-export for ergonomic destructuring + the empty-value sentinel.
export { ARTICLE_BODY_EMPTY_VALUE };

export { ArticleBodyEditor } from "./article-body-01";
export { ArticleBodyViewer } from "./article-body-viewer";
export {
  ARTICLE_BODY_DEFAULT_PLACEHOLDER,
  ARTICLE_BODY_EMPTY_VALUE,
  type ArticleBodyEditorProps,
  type ArticleBodyValue,
  type ArticleBodyViewerProps,
  type ImageUploadResult,
  type ImageUploader,
} from "./types";
export { meta } from "./meta";

import type { ReactNode } from "react";
import type { Value } from "platejs";

export type ArticleBodyValue = Value;

export interface ImageUploadResult {
  src: string;
  alt?: string;
  width?: number;
  height?: number;
}

export type ImageUploader = (file: File) => Promise<ImageUploadResult>;

export interface ArticleBodyEditorProps {
  value?: ArticleBodyValue;
  defaultValue?: ArticleBodyValue;
  onChange?: (value: ArticleBodyValue) => void;
  onSave?: (value: ArticleBodyValue) => void | Promise<void>;
  readOnly?: boolean;
  placeholder?: string;
  onImageUpload?: ImageUploader;
  className?: string;
  toolbarClassName?: string;
  contentClassName?: string;
  containerClassName?: string;
  hideToolbar?: boolean;
  autoFocus?: boolean;
}

export interface ArticleBodyViewerProps {
  value: ArticleBodyValue;
  className?: string;
  fallback?: ReactNode;
}

export const ARTICLE_BODY_EMPTY_VALUE: ArticleBodyValue = [
  { type: "p", children: [{ text: "" }] },
];

export const ARTICLE_BODY_DEFAULT_PLACEHOLDER = "Write your article here…";

"use client";

import {
  BlockquotePlugin,
  BoldPlugin,
  CodePlugin,
  H1Plugin,
  H2Plugin,
  H3Plugin,
  H4Plugin,
  HighlightPlugin,
  HorizontalRulePlugin,
  ItalicPlugin,
  KbdPlugin,
  StrikethroughPlugin,
  SubscriptPlugin,
  SuperscriptPlugin,
  UnderlinePlugin,
} from "@platejs/basic-nodes/react";
import {
  FontBackgroundColorPlugin,
  FontColorPlugin,
  FontFamilyPlugin,
  FontSizePlugin,
} from "@platejs/basic-styles/react";
import { CodeBlockPlugin, CodeLinePlugin, CodeSyntaxPlugin } from "@platejs/code-block/react";
import { IndentPlugin } from "@platejs/indent/react";
import { LinkPlugin } from "@platejs/link/react";
import { ListPlugin } from "@platejs/list/react";
import { ImagePlugin, MediaEmbedPlugin } from "@platejs/media/react";
import {
  TableCellHeaderPlugin,
  TableCellPlugin,
  TablePlugin,
  TableRowPlugin,
} from "@platejs/table/react";
import { ParagraphPlugin } from "platejs/react";

import {
  BlockquoteElement,
  CodeBlockElement,
  CodeLineElement,
  H1Element,
  H2Element,
  H3Element,
  H4Element,
  HrElement,
  ImageElement,
  LinkElement,
  ListElement,
  MediaEmbedElement,
  ParagraphElement,
  TableCellElement,
  TableCellHeaderElement,
  TableElement,
  TableRowElement,
} from "../parts/element-renderers";
import {
  CodeLeaf,
  HighlightLeaf,
  KbdLeaf,
} from "../parts/leaf-renderers";

/**
 * The plugin set for the editor side.
 * The viewer reuses these plugin definitions via createSlateEditor + components map
 * (see article-body-viewer.tsx) so element/leaf rendering stays consistent.
 */
export const articleBodyPlugins = [
  // Blocks
  ParagraphPlugin.withComponent(ParagraphElement),
  H1Plugin.withComponent(H1Element),
  H2Plugin.withComponent(H2Element),
  H3Plugin.withComponent(H3Element),
  H4Plugin.withComponent(H4Element),
  BlockquotePlugin.withComponent(BlockquoteElement),
  HorizontalRulePlugin.withComponent(HrElement),

  // Lists
  ListPlugin.withComponent(ListElement),

  // Code blocks
  CodeBlockPlugin.withComponent(CodeBlockElement),
  CodeLinePlugin.withComponent(CodeLineElement),
  CodeSyntaxPlugin,

  // Tables
  TablePlugin.withComponent(TableElement),
  TableRowPlugin.withComponent(TableRowElement),
  TableCellPlugin.withComponent(TableCellElement),
  TableCellHeaderPlugin.withComponent(TableCellHeaderElement),

  // Media
  ImagePlugin.withComponent(ImageElement),
  MediaEmbedPlugin.withComponent(MediaEmbedElement),

  // Inline
  LinkPlugin.withComponent(LinkElement),

  // Marks
  BoldPlugin,
  ItalicPlugin,
  UnderlinePlugin,
  StrikethroughPlugin,
  CodePlugin.withComponent(CodeLeaf),
  HighlightPlugin.withComponent(HighlightLeaf),
  SubscriptPlugin,
  SuperscriptPlugin,
  KbdPlugin.withComponent(KbdLeaf),

  // Styles (text-level attributes — no element component)
  FontFamilyPlugin,
  FontSizePlugin,
  FontColorPlugin,
  FontBackgroundColorPlugin,

  // Layout
  IndentPlugin.configure({
    inject: {
      targetPlugins: [
        ParagraphPlugin.key,
        H1Plugin.key,
        H2Plugin.key,
        H3Plugin.key,
        H4Plugin.key,
        BlockquotePlugin.key,
        CodeBlockPlugin.key,
      ],
    },
  }),
];

"use client";

import {
  Bold,
  Code,
  Heading1,
  Heading2,
  Heading3,
  Highlighter,
  Image as ImageIcon,
  Italic,
  Link as LinkIcon,
  List,
  ListOrdered,
  Minus,
  Quote,
  Strikethrough,
  Subscript as SubIcon,
  Superscript as SupIcon,
  Table as TableIcon,
  TerminalSquare,
  Underline as UnderlineIcon,
} from "lucide-react";
import {
  BoldPlugin,
  CodePlugin,
  H1Plugin,
  H2Plugin,
  H3Plugin,
  HighlightPlugin,
  HorizontalRulePlugin,
  ItalicPlugin,
  StrikethroughPlugin,
  SubscriptPlugin,
  SuperscriptPlugin,
  UnderlinePlugin,
} from "@platejs/basic-nodes/react";
import {
  type ComponentType,
  type MouseEvent,
  type ReactNode,
  useCallback,
} from "react";
import { CodeBlockPlugin } from "@platejs/code-block/react";
import { LinkPlugin } from "@platejs/link/react";
import { ListPlugin } from "@platejs/list/react";
import { ImagePlugin } from "@platejs/media/react";
import { TablePlugin } from "@platejs/table/react";
import {
  ParagraphPlugin,
  useEditorRef,
  useEditorSelector,
  useMarkToolbarButton,
  useMarkToolbarButtonState,
} from "platejs/react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { ImageUploader } from "../types";

interface MarkButtonProps {
  nodeType: string;
  icon: ComponentType<{ className?: string }>;
  label: string;
}

function MarkButton({ nodeType, icon: Icon, label }: MarkButtonProps) {
  const state = useMarkToolbarButtonState({ nodeType });
  const { props } = useMarkToolbarButton(state);
  return (
    <Button
      type="button"
      variant="ghost"
      size="icon"
      className={cn(
        "h-8 w-8",
        state.pressed && "bg-muted text-foreground"
      )}
      title={label}
      aria-label={label}
      aria-pressed={state.pressed}
      onMouseDown={props.onMouseDown}
      onClick={props.onClick}
    >
      <Icon className="h-4 w-4" />
    </Button>
  );
}

interface BlockButtonProps {
  isActive: boolean;
  onActivate: () => void;
  icon: ComponentType<{ className?: string }>;
  label: string;
}

function BlockButton({ isActive, onActivate, icon: Icon, label }: BlockButtonProps) {
  const handleMouseDown = useCallback((e: MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
  }, []);

  return (
    <Button
      type="button"
      variant="ghost"
      size="icon"
      className={cn(
        "h-8 w-8",
        isActive && "bg-muted text-foreground"
      )}
      title={label}
      aria-label={label}
      aria-pressed={isActive}
      onMouseDown={handleMouseDown}
      onClick={onActivate}
    >
      <Icon className="h-4 w-4" />
    </Button>
  );
}

function useBlockToggle(blockType: string) {
  const editor = useEditorRef();
  const isActive = useEditorSelector(
    (e) => {
      const entry = e.api.block();
      return entry?.[0]?.type === blockType;
    },
    [blockType]
  );
  const toggle = useCallback(() => {
    editor.tf.toggleBlock(blockType);
    editor.tf.focus();
  }, [editor, blockType]);
  return { isActive, toggle };
}

function HeadingButton({
  blockType,
  icon,
  label,
}: {
  blockType: string;
  icon: ComponentType<{ className?: string }>;
  label: string;
}) {
  const { isActive, toggle } = useBlockToggle(blockType);
  return <BlockButton isActive={isActive} onActivate={toggle} icon={icon} label={label} />;
}

function InsertHrButton() {
  const editor = useEditorRef();
  const handleClick = useCallback(() => {
    editor.tf.insertNodes({
      type: HorizontalRulePlugin.key,
      children: [{ text: "" }],
    });
    editor.tf.focus();
  }, [editor]);
  return (
    <BlockButton
      isActive={false}
      onActivate={handleClick}
      icon={Minus}
      label="Insert horizontal rule"
    />
  );
}

function InsertListButton({ ordered }: { ordered: boolean }) {
  const editor = useEditorRef();
  const handleClick = useCallback(() => {
    editor.tf.insertNodes({
      type: ListPlugin.key,
      listStyleType: ordered ? "decimal" : "disc",
      indent: 1,
      children: [{ text: "" }],
    });
    editor.tf.focus();
  }, [editor, ordered]);
  return (
    <BlockButton
      isActive={false}
      onActivate={handleClick}
      icon={ordered ? ListOrdered : List}
      label={ordered ? "Insert ordered list" : "Insert bullet list"}
    />
  );
}

function InsertTableButton() {
  const editor = useEditorRef();
  const handleClick = useCallback(() => {
    const cell = (text = "") => ({
      type: "td",
      children: [{ type: ParagraphPlugin.key, children: [{ text }] }],
    });
    const headerCell = (text = "") => ({
      type: "th",
      children: [{ type: ParagraphPlugin.key, children: [{ text }] }],
    });
    editor.tf.insertNodes({
      type: TablePlugin.key,
      children: [
        { type: "tr", children: [headerCell("Column 1"), headerCell("Column 2"), headerCell("Column 3")] },
        { type: "tr", children: [cell(), cell(), cell()] },
        { type: "tr", children: [cell(), cell(), cell()] },
      ],
    });
    editor.tf.focus();
  }, [editor]);
  return (
    <BlockButton
      isActive={false}
      onActivate={handleClick}
      icon={TableIcon}
      label="Insert table"
    />
  );
}

function InsertImageButton({ onImageUpload }: { onImageUpload?: ImageUploader }) {
  const editor = useEditorRef();

  const handleClick = useCallback(async () => {
    if (onImageUpload) {
      const input = document.createElement("input");
      input.type = "file";
      input.accept = "image/*";
      input.onchange = async () => {
        const file = input.files?.[0];
        if (!file) return;
        try {
          const result = await onImageUpload(file);
          editor.tf.insertNodes({
            type: ImagePlugin.key,
            url: result.src,
            alt: result.alt ?? file.name,
            width: result.width,
            height: result.height,
            children: [{ text: "" }],
          });
          editor.tf.focus();
        } catch (err) {
          console.error("Image upload failed", err);
        }
      };
      input.click();
      return;
    }

    const url = window.prompt("Image URL");
    if (!url) return;
    editor.tf.insertNodes({
      type: ImagePlugin.key,
      url,
      children: [{ text: "" }],
    });
    editor.tf.focus();
  }, [editor, onImageUpload]);

  return (
    <BlockButton
      isActive={false}
      onActivate={handleClick}
      icon={ImageIcon}
      label="Insert image"
    />
  );
}

function InsertLinkButton() {
  const editor = useEditorRef();
  const handleClick = useCallback(() => {
    const url = window.prompt("Link URL");
    if (!url) return;
    const text = window.getSelection()?.toString() || url;
    editor.tf.insertNodes({
      type: LinkPlugin.key,
      url,
      children: [{ text }],
    });
    editor.tf.focus();
  }, [editor]);
  return (
    <BlockButton
      isActive={false}
      onActivate={handleClick}
      icon={LinkIcon}
      label="Insert link"
    />
  );
}

function FontFamilySelect() {
  const editor = useEditorRef();
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLSelectElement>) => {
      const value = e.target.value;
      if (value === "default") {
        editor.tf.removeMark("fontFamily");
      } else {
        editor.tf.addMark("fontFamily", value);
      }
      editor.tf.focus();
    },
    [editor]
  );
  return (
    <select
      onMouseDown={(e) => e.preventDefault()}
      onChange={handleChange}
      className="h-8 rounded-md border border-input bg-background px-2 text-xs"
      title="Font family"
      aria-label="Font family"
      defaultValue="default"
    >
      <option value="default">Default font</option>
      <option value="var(--font-serif)">Serif</option>
      <option value="var(--font-sans)">Sans</option>
      <option value="var(--font-mono)">Mono</option>
    </select>
  );
}

function FontSizeSelect() {
  const editor = useEditorRef();
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLSelectElement>) => {
      const value = e.target.value;
      if (value === "default") {
        editor.tf.removeMark("fontSize");
      } else {
        editor.tf.addMark("fontSize", value);
      }
      editor.tf.focus();
    },
    [editor]
  );
  return (
    <select
      onMouseDown={(e) => e.preventDefault()}
      onChange={handleChange}
      className="h-8 rounded-md border border-input bg-background px-2 text-xs"
      title="Font size"
      aria-label="Font size"
      defaultValue="default"
    >
      <option value="default">Size</option>
      <option value="12px">12</option>
      <option value="14px">14</option>
      <option value="16px">16</option>
      <option value="18px">18</option>
      <option value="20px">20</option>
      <option value="24px">24</option>
      <option value="32px">32</option>
    </select>
  );
}

function FontColorInput() {
  const editor = useEditorRef();
  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      editor.tf.addMark("color", e.target.value);
      editor.tf.focus();
    },
    [editor]
  );
  return (
    <input
      type="color"
      onMouseDown={(e) => e.preventDefault()}
      onChange={handleChange}
      className="h-8 w-8 cursor-pointer rounded-md border border-input bg-background"
      title="Text color"
      aria-label="Text color"
      defaultValue="#000000"
    />
  );
}

function ToolbarSeparator() {
  return <span className="mx-1 h-6 w-px bg-border" aria-hidden="true" />;
}

function ToolbarGroup({ children }: { children: ReactNode }) {
  return <div className="flex items-center gap-0.5">{children}</div>;
}

interface EditorToolbarProps {
  className?: string;
  onImageUpload?: ImageUploader;
}

export function EditorToolbar({ className, onImageUpload }: EditorToolbarProps) {
  return (
    <div
      role="toolbar"
      aria-label="Article body editor toolbar"
      className={cn(
        "flex flex-wrap items-center gap-1 border-b border-border bg-card px-2 py-1.5",
        className
      )}
    >
      <ToolbarGroup>
        <MarkButton nodeType={BoldPlugin.key} icon={Bold} label="Bold" />
        <MarkButton nodeType={ItalicPlugin.key} icon={Italic} label="Italic" />
        <MarkButton nodeType={UnderlinePlugin.key} icon={UnderlineIcon} label="Underline" />
        <MarkButton nodeType={StrikethroughPlugin.key} icon={Strikethrough} label="Strikethrough" />
        <MarkButton nodeType={CodePlugin.key} icon={Code} label="Inline code" />
        <MarkButton nodeType={HighlightPlugin.key} icon={Highlighter} label="Highlight" />
        <MarkButton nodeType={SubscriptPlugin.key} icon={SubIcon} label="Subscript" />
        <MarkButton nodeType={SuperscriptPlugin.key} icon={SupIcon} label="Superscript" />
      </ToolbarGroup>

      <ToolbarSeparator />

      <ToolbarGroup>
        <HeadingButton blockType={H1Plugin.key} icon={Heading1} label="Heading 1" />
        <HeadingButton blockType={H2Plugin.key} icon={Heading2} label="Heading 2" />
        <HeadingButton blockType={H3Plugin.key} icon={Heading3} label="Heading 3" />
      </ToolbarGroup>

      <ToolbarSeparator />

      <ToolbarGroup>
        <HeadingButton blockType="blockquote" icon={Quote} label="Blockquote" />
        <HeadingButton blockType={CodeBlockPlugin.key} icon={TerminalSquare} label="Code block" />
        <InsertHrButton />
      </ToolbarGroup>

      <ToolbarSeparator />

      <ToolbarGroup>
        <InsertListButton ordered={false} />
        <InsertListButton ordered />
      </ToolbarGroup>

      <ToolbarSeparator />

      <ToolbarGroup>
        <InsertLinkButton />
        <InsertImageButton onImageUpload={onImageUpload} />
        <InsertTableButton />
      </ToolbarGroup>

      <ToolbarSeparator />

      <ToolbarGroup>
        <FontFamilySelect />
        <FontSizeSelect />
        <FontColorInput />
      </ToolbarGroup>
    </div>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { PlateElement, type PlateElementProps } from "platejs/react";
import { cn } from "@/lib/utils";

type ElementProps = ComponentProps<typeof PlateElement>;

// Plate's `<PlateElement as="X">` discriminates the type of `attributes` per
// HTML element kind. When we forward `props.attributes` (typed for a wider
// element kind), TS rejects the narrower target. The runtime is just data-slate-*
// attributes — fine on any HTML element. Cast via this helper.
//
// Without this we'd pepper `attributes={props.attributes as never}` on every
// element. One central cast keeps the noise local.
function withAs<As extends string>(props: ElementProps, as: As): ElementProps & { as: As } {
  // The cast is intentional: we know `props.attributes` is the same data-slate-*
  // shape regardless of `as`. TS's discriminated-union narrowing doesn't help here.
  return { ...props, as, attributes: props.attributes as never } as ElementProps & {
    as: As;
  };
}

function Wrapped(props: ElementProps & { as?: string; className?: string; children: ReactNode }) {
  return <PlateElement {...(props as ElementProps)}>{props.children}</PlateElement>;
}

export function ParagraphElement(props: ElementProps) {
  return (
    <Wrapped {...withAs(props, "p")} className={cn("my-4 leading-relaxed", props.className)}>
      {props.children}
    </Wrapped>
  );
}

export function H1Element(props: ElementProps) {
  return (
    <Wrapped {...withAs(props, "h1")} className={cn("mt-10 mb-4 text-4xl font-serif font-bold tracking-tight", props.className)}>
      {props.children}
    </Wrapped>
  );
}

export function H2Element(props: ElementProps) {
  return (
    <Wrapped {...withAs(props, "h2")} className={cn("mt-8 mb-3 text-3xl font-serif font-bold tracking-tight", props.className)}>
      {props.children}
    </Wrapped>
  );
}

export function H3Element(props: ElementProps) {
  return (
    <Wrapped {...withAs(props, "h3")} className={cn("mt-6 mb-2 text-2xl font-serif font-bold", props.className)}>
      {props.children}
    </Wrapped>
  );
}

export function H4Element(props: ElementProps) {
  return (
    <Wrapped {...withAs(props, "h4")} className={cn("mt-4 mb-2 text-xl font-serif font-semibold", props.className)}>
      {props.children}
    </Wrapped>
  );
}

export function BlockquoteElement(props: ElementProps) {
  return (
    <Wrapped
      {...withAs(props, "blockquote")}
      className={cn(
        "my-6 border-l-4 border-primary pl-6 py-2 italic text-muted-foreground bg-muted/30 rounded-r-md",
        props.className
      )}
